        defaultCode: '<div class="container mt-4">\n  <h5 class="mb-3">Tooltips</h5>\n  <p class="mb-4">Hover over the buttons below to see tooltips.</p>\n  <div class="d-flex gap-2 mb-4 flex-wrap">\n    <button type="button" class="btn btn-secondary" data-bs-toggle="tooltip" data-bs-placement="top" title="Tooltip on top">Top</button>\n    <button type="button" class="btn btn-secondary" data-bs-toggle="tooltip" data-bs-placement="right" title="Tooltip on right">Right</button>\n    <button type="button" class="btn btn-secondary" data-bs-toggle="tooltip" data-bs-placement="bottom" title="Tooltip on bottom">Bottom</button>\n    <button type="button" class="btn btn-secondary" data-bs-toggle="tooltip" data-bs-placement="left" title="Tooltip on left">Left</button>\n  </div>\n  <hr>\n  <h5 class="mb-3">Popovers</h5>\n  <p>Click the buttons to toggle popovers.</p>\n  <div class="d-flex gap-2 flex-wrap">\n    <button type="button" class="btn btn-primary" data-bs-toggle="popover" data-bs-title="Popover title" data-bs-content="And here\'s some amazing content. It\'s very engaging." data-bs-placement="right">Click me</button>\n    <button type="button" class="btn btn-success" data-bs-toggle="popover" data-bs-title="Another title" data-bs-content="More content to display.">Another</button>\n  </div>\n  <script>\n    var tooltipList = [].slice.call(document.querySelectorAll("[data-bs-toggle=\"tooltip\"]")).map(function(el) { return new bootstrap.Tooltip(el); });\n    var popoverList = [].slice.call(document.querySelectorAll("[data-bs-toggle=\"popover\"]")).map(function(el) { return new bootstrap.Popover(el); });\n  </script>\n</div>',
