          '  &lt;section class="about"&gt;&lt;!-- Grid + typography --&gt;&lt;/section&gt;',
          '  &lt;section class="contact"&gt;&lt;!-- Form --&gt;&lt;/section&gt;',
          '&lt;/main&gt;',
